import React from 'react';
import { AISkeleton as CarbonAISkeleton } from '@carbon/react';

const AISkeleton = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonAISkeleton
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonAISkeleton>
    );
};

AISkeleton.defaultProps = {
    className: ''
};

export default AISkeleton;
